function sanitizeSlackMrkdwn(text) {
  return String(text || '')
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>');
}

const output = $json.output || [];
const rawText = (output[0]?.content || []).find(c => c.type === 'output_text')?.text || '';
const date = new Date().toISOString().split('T')[0];
const header = '*QA Security Scan — ' + date + '*\n\n';
const footer = '\n\n_Thread router: reply with a persona name for a focused take._';
const fallback = ':warning: No output generated. Check workflow logs.';
let body;
if (!rawText.trim()) {
  body = fallback;
} else {
  try {
    const data = JSON.parse(rawText);
    const sections = [];
    for (const [key, value] of Object.entries(data)) {
      const label = key.split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
      if (Array.isArray(value)) {
        sections.push('*' + label + '*\n' + value.map(v => '\u2022 ' + (typeof v === 'object' ? (v.description || v.title || JSON.stringify(v)) : String(v))).join('\n'));
      } else if (typeof value === 'object' && value !== null) {
        sections.push('*' + label + '*\n' + Object.entries(value).map(([k, v]) => '\u2022 *' + k + '*: ' + String(v)).join('\n'));
      } else {
        sections.push('*' + label + '*: ' + String(value));
      }
    }
    body = sections.join('\n\n');
  } catch (e) {
    body = rawText;
  }
}
return [{ json: { text: header + body + footer, rawText: rawText || fallback, date } }];
